@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent {
  title = 'gestor-dinero';
}
<header class="main-header">

  <app-navbar></app-navbar>
</header>

<div id="route-outler">
  <router-outlet></router-outlet>
</div>
